SELECT id, title, content, publisher_id, type, status,
       create_time, update_time
FROM sys_notice
WHERE 1 = 1

    AND type = #{type}


    AND status = #{status}

ORDER BY create_time DESC
LIMIT #{offset}, #{size}

SELECT COUNT(*)
FROM sys_notice
WHERE 1 = 1

    AND type = #{type}


    AND status = #{status}
